// CORRECT: status(1) → lock(2) → invoice(3) → charge(4)
const sub = await this.billingService.getStatus(subscriptionId);
if (['CANCELLED','PAUSED'].includes(sub.status)) { await emit('InvoiceVoided'); return; }
const locked = await this.billingService.lock(subscriptionId, periodKey);
if (!locked) return;
const invoiceId = hash(tenantId+subscriptionId+periodKey);
const result = await this.paymentService.charge({ amount, invoiceId, attemptNumber });

// CORRECT: integer guard at ORDER 1
if (!Number.isInteger(event.priceCents) || event.priceCents <= 0) {
  return DataProcessResult.failure('INVALID_PRICE', 'priceCents must be a positive integer');
}

// CORRECT: FREEDOM config dunning
const schedule = await this.freedomConfig.get('subscription_billing_dunning_schedule');
if (attemptNumber >= schedule.length) { await emit('DunningFailed'); return; }
const waitMs = schedule[attemptNumber].wait_hours * 3600000;
await this.billingService.scheduleNext(subscriptionId, Date.now() + waitMs, attemptNumber + 1);

function normalizeMrr(priceCents, billingInterval, intervalDays) {
  switch(billingInterval) {
    case 'MONTHLY': return priceCents;
    case 'ANNUAL':  return Math.floor(priceCents / 12);
    case 'CUSTOM':  return Math.floor(priceCents / (intervalDays ?? 30) * 30);
  }
}
